def create_kong_service(service_name, host, port):
    url = f"http://{kong_host}:{kong_port}/services"
    payload = {
        "name": service_name,
        "host": host,
        "port": str(port)
    }
    headers = {"Content-Type": "application/json"}
    
    if api_key:
        headers['Authorization'] = 'Bearer ' + api_key
        
    response = requests.post(url, json=payload, headers=headers)
    
    print(f"Response creating service: {response.text}")

def create_kong_route(service_name):
    url = f"http://{kong_host}:{kong_port}/routes"
    payload = {
        "consumes": ["application/json"],
        "produces": ["application/json"],
        "protocols": ["http", "https"],
        "paths": ["/"]
    }
    
    headers = {"Content-Type": "application/json"}
    
    if api_key:
        headers['Authorization'] = 'Bearer ' + api_key
        
    response = requests.post(url, json=payload, headers=headers)
    route_id = None
    
    for r in response.json()['routes']:
        if service_name in r['service']['name']:
            route_id = r['id']
    
    payload['service']['id'] = f'service:{service_name}'
    
    # update the route
    url = f"http://{kong_host}:{kong_port}/routes/{route_id}"
    response = requests.put(url, json=payload, headers=headers)
    
    print(f"Response creating route: {response.text}")

def create_kong_upstream(service_name):
    url = f"http://{kong_host}:{kong_port}/services/{service_name}/upstreams"
    payload = {
        "name": service_name,
        "algorithm": 'round-robin'
    }
    
    headers = {"Content-Type": "application/json"}
    
    if api_key:
        headers['Authorization'] = 'Bearer ' + api_key
        
    response = requests.post(url, json=payload, headers=headers)
    
    upstream_id = response.json()['upstreams'][0]['id']
    
    payload = {
        "pools": [
            {"upstream": f"service:{service_name}", "data": {"port": 80}, "weight": 1}
        ]
    }
    
    url = f"http://{kong_host}:{kong_port}/upstreams/{upstream_id}"
    response = requests.put(url, json=payload, headers=headers)
    
    print(f"Response creating upstream: {response.text}")

